#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=105;
int n,m,vis[N],mx,dep[N];
vector<int> g[N];
void dfs(int u,int f)
{
	vis[u]=1;
	dep[u]=dep[f]+1;
	mx=max(mx,dep[u]);
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(vis[v]) continue;
		dfs(v,u);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dep[N-1]=0;
	dfs(0,N-1);
	if(m<mx) cout<<m+1;
	else cout<<min(n,mx+(m-mx+1)/2);
	return 0;
}
